using UnityEngine;

// Base class (parent)
public class Character
{
    public string name;
    public int health;
    public int attackPower;
    public int defense;

    public Character(string charName, int startingHealth)
    {
        name = charName;
        health = startingHealth;
        attackPower = 10;
        defense = 5;
        Debug.Log("Character created: " + name);
    }

    public virtual void Attack(Character target)
    {
        int damage = Mathf.Max(attackPower - target.defense, 1);
        target.TakeDamage(damage);
        Debug.Log(name + " attacks " + target.name + " for " + damage + " damage!");
    }

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
        Debug.Log(name + " took " + damage + " damage! Health: " + health);
    }

    public virtual void DisplayStats()
    {
        Debug.Log("=== " + name + " ===");
        Debug.Log("Health: " + health);
        Debug.Log("Attack: " + attackPower);
        Debug.Log("Defense: " + defense);
    }
}

// Derived class (child) — inherits from Character
public class Warrior : Character
{
    public int rage;

    public Warrior(string name) : base(name, 120)
    {
        rage = 0;
        attackPower = 15;
        defense = 8;
        Debug.Log("Warrior " + name + " created!");
    }

    public override void Attack(Character target)
    {
        // Rage increases damage
        int bonus = rage;
        int damage = Mathf.Max(attackPower + bonus - target.defense, 1);
        target.TakeDamage(damage);
        rage += 5;
        Debug.Log(name + " (Warrior) attacks " + target.name + " for " + damage + " damage! Rage: " + rage);
    }
}

// Another derived class
public class Mage : Character
{
    public int mana;

    public Mage(string name) : base(name, 80)
    {
        mana = 100;
        attackPower = 18;
        defense = 3;
        Debug.Log("Mage " + name + " created!");
    }

    public override void Attack(Character target)
    {
        if (mana >= 20)
        {
            int damage = Mathf.Max(attackPower * 2 - target.defense, 1);
            target.TakeDamage(damage);
            mana -= 20;
            Debug.Log(name + " (Mage) casts fireball on " + target.name + " for " + damage + " damage! Mana: " + mana);
        }
        else
        {
            Debug.Log(name + " is out of mana!");
            base.Attack(target);  // Use base class attack
        }
    }
}

public class InheritanceExample : MonoBehaviour
{
    void Start()
    {
        Warrior hero = new Warrior("Aragorn");
        Mage enemy = new Mage("Goblin Mage");

        hero.DisplayStats();
        enemy.DisplayStats();

        hero.Attack(enemy);
        enemy.Attack(hero);
    }
}

